#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 100000
#define MAXQ 100000
int dp[MAXN][MAXN];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int impassable[N][2];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &impassable[i][0], &impassable[i][1]);
        }
        int Q;
        scanf("%d", &Q);
        int games[Q][2];
        for (int i = 0; i < Q; i++) {
            scanf("%d %d", &games[i][0], &games[i][1]);
        }
        // Initialize dp array
        for (int i = 0; i < MAXN; i++) {
            for (int j = 0; j < MAXN; j++) {
                dp[i][j] = -1;
            }
        }
        // Fill up dp array
        for (int i = 0; i < MAXN; i++) {
            for (int j = 0; j < MAXN; j++) {
                if (i == 0 && j == 0) {
                    dp[i][j] = 1;
                } else {
                    int winner = 0;
                    for (int k = 1; k <= i; k++) {
                        if (dp[i - k][j] == 0) {
                            winner = 1;
                            break;
                        }
                    }
                    for (int k = 1; k <= j; k++) {
                        if (dp[i][j - k] == 0) {
                            winner = 1;
                            break;
                        }
                    }
                    dp[i][j] = winner;
                }
            }
        }
        // Determine winner of each game
        for (int i = 0; i < Q; i++) {
            if (dp[games[i][0]][games[i][1]] == 1) {
                printf("Alice\n");
            } else {
                printf("Bob\n");
            }
        }
    }
    return 0;
}

